const items = $input.all();
if (!items || items.length === 0) {
  throw new Error('No data received from Google Sheets. Check the sheet ID, tab name, and permissions.');
}
for (let i = 0; i < items.length; i++) {
  const row = items[i].json;
  const keys = Object.keys(row).filter(k => k !== 'row_number');
  const colA = keys[0];
  const colB = keys[1];
  const colC = keys.length > 2 ? keys[2] : null;
  if (colB && row[colB] && row[colB].toString().toLowerCase().trim() === 'pending' && row[colA] && row[colA].toString().trim()) {
    const topic = row[colA].toString().trim();
    return [{json:{topic, rowNumber: row.row_number || (i + 2), colA, colB, colC}}];
  }
}
throw new Error('No pending topics found in the Veganster Topics sheet.');

const text = $input.first().json.text;
if (!text) throw new Error('No content received from Gemini. Check the AI model response.');

let clean = text.trim();
if (clean.startsWith('```')) {
  clean = clean.replace(/^```(?:md|markdown|mdx)?\n?/, '').replace(/\n?```$/, '').trim();
}

let articleTitle = '';
const tm = clean.match(/^title:\s*(.+)$/m);
if (tm) articleTitle = tm[1].trim().replace(/^["']|["']$/g, '');

const stopWords = new Set(['the','a','an','of','to','in','for','and','or','with','on','your','my','this','that','is','are','be','from','at','by','how','why','what','when','best','top','guide']);
const words = (articleTitle || '').toLowerCase().split(/[^a-z0-9]+/).filter(w => w && !stopWords.has(w));
const searchKeywords = words.slice(0, 4).join(' ') || 'plant based food';

const ctx = $('Inject Today\'s Date').first().json;

return [{
  json: {
    topic: ctx.topic,
    rowNumber: ctx.rowNumber,
    colA: ctx.colA,
    colB: ctx.colB,
    colC: ctx.colC,
    todayDate: ctx.todayDate,
    articleTitle: articleTitle || ctx.topic,
    searchKeywords,
    articleContent: clean
  }
}];

const t = $('Process Unsplash, Generate Slug & Encode').first().json;
const row = {};
row[t.colA] = t.topic;
row[t.colB] = 'used';
if (t.colC) row[t.colC] = t.todayDate;
return [{json: row}];

// =============================================================
// Multi-query Unsplash search with hardcoded image pool fallback.
// Tries 3 progressively broader queries; if all return empty,
// picks a random image from a 12-photo pre-curated vegan pool.
// =============================================================
const stripData = $input.first().json;
const title = stripData.articleTitle || stripData.topic || '';

const stopWords = new Set(['the','a','an','of','to','in','for','and','or','with','on','your','my','this','that','is','are','be','from','at','by','how','why','what','when','best','top','guide','should','eat','daily','science','behind','ultimate','complete','beginner','beginners']);
const titleWords = title.toLowerCase().split(/[^a-z0-9]+/).filter(w => w && !stopWords.has(w));

// --- Query 1: smart 1-2 word query targeting a food/ingredient ---
const foodKeywords = ['protein','quinoa','kale','tofu','tempeh','bean','lentil','rice','oat','chickpea','spinach','broccoli','avocado','smoothie','salad','breakfast','lunch','dinner','meal','soup','curry','pasta','burger','wrap','bowl','vegetable','fruit','berry','nut','seed','grain','bread','dessert','cookie','cake','pizza','tomato','pepper','mushroom','cabbage','carrot','potato','tea','coffee','juice','milk','butter','yogurt','cheese','flax','chia','hemp','almond','walnut','cashew'];
const foodMatch = titleWords.find(w => foodKeywords.some(kw => w === kw || w.startsWith(kw)));
let smartQuery;
if (foodMatch) {
  smartQuery = 'vegan ' + foodMatch;
} else {
  smartQuery = (titleWords.slice(0, 2).join(' ') || 'plant based') + ' vegan';
}

// --- Query 2: broader category-derived term ---
const categoryMap = {
  breakfast: 'vegan breakfast', lunch: 'vegan lunch', dinner: 'vegan dinner',
  dessert: 'vegan dessert', snack: 'vegan snack', drink: 'smoothie healthy',
  smoothie: 'smoothie bowl', salad: 'fresh salad', soup: 'vegan soup',
  bowl: 'plant based bowl', protein: 'plant based protein', proteins: 'plant based protein',
  inflammation: 'fresh vegetables', inflammatory: 'fresh vegetables',
  wellness: 'healthy lifestyle', health: 'healthy food', nutrition: 'fresh fruits vegetables',
  gut: 'fermented vegetables', immune: 'colorful vegetables', energy: 'fresh fruits',
  iron: 'leafy greens', vitamin: 'fresh vegetables',
  superfood: 'colorful fruits vegetables', superfoods: 'colorful fruits vegetables',
};
let broaderQuery = 'plant based meal';
for (const w of titleWords) {
  if (categoryMap[w]) { broaderQuery = categoryMap[w]; break; }
}

// --- Query 3: random pick from guaranteed-result generic terms ---
const fallbackTerms = ['vegan food','plant based meal','vegetables fresh','healthy salad','vegan bowl','fruits vegetables','plant based protein','vegan cooking'];
const randomTerm = fallbackTerms[Math.floor(Math.random() * fallbackTerms.length)];

const queries = [smartQuery, broaderQuery, randomTerm];

let imageUrl = null;
let credit = '';
let creditUrl = '';
let usedQuery = '';
let usedFallback = false;
const attempted = [];

for (const q of queries) {
  attempted.push(q);
  try {
    const response = await this.helpers.httpRequestWithAuthentication.call(this, 'httpHeaderAuth', {
      method: 'GET',
      url: 'https://api.unsplash.com/search/photos',
      qs: { query: q, per_page: 1, orientation: 'landscape' },
      json: true,
    });
    if (response && response.results && response.results.length > 0) {
      const f = response.results[0];
      if (f.urls && f.urls.regular) {
        const u = new URL(f.urls.regular);
        ['w','h','fit','fm','q','crop','cs','ixid','ixlib','auto','dpr'].forEach(p => u.searchParams.delete(p));
        u.searchParams.set('w', '1200');
        u.searchParams.set('h', '800');
        u.searchParams.set('fit', 'crop');
        u.searchParams.set('fm', 'webp');
        u.searchParams.set('q', '80');
        imageUrl = u.toString();
        const photographerName = (f.user && f.user.name) ? f.user.name : '';
        const photoUrl = (f.links && f.links.html) ? f.links.html : '';
        credit = photographerName ? ('Photo by ' + photographerName + ' on Unsplash') : 'Unsplash';
        creditUrl = photoUrl || 'https://unsplash.com';
        usedQuery = q;
        break;
      }
    }
  } catch (e) {
    // try next query
  }
}

// --- Final fallback: pick a random image from a hardcoded pool ---
if (!imageUrl) {
  const pool = [
    { url: 'https://images.unsplash.com/photo-1498837167922-ddd27525d352?w=1200&h=800&fit=crop&fm=webp&q=80', credit: 'Photo by Dan Gold on Unsplash', creditUrl: 'https://unsplash.com/photos/4_jhDO54BYg' },
    { url: 'https://images.unsplash.com/photo-1490645935967-10de6ba17061?w=1200&h=800&fit=crop&fm=webp&q=80', credit: 'Photo by Brooke Lark on Unsplash', creditUrl: 'https://unsplash.com/photos/08bOYnH_r_E' },
    { url: 'https://images.unsplash.com/photo-1512621776951-a57141f2eefd?w=1200&h=800&fit=crop&fm=webp&q=80', credit: 'Photo by Brooke Lark on Unsplash', creditUrl: 'https://unsplash.com/photos/W1B2LpQOBxA' },
    { url: 'https://images.unsplash.com/photo-1505253758473-96b7015fcd40?w=1200&h=800&fit=crop&fm=webp&q=80', credit: 'Photo by Anna Pelzer on Unsplash', creditUrl: 'https://unsplash.com/photos/IGfIGP5ONV0' },
    { url: 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=1200&h=800&fit=crop&fm=webp&q=80', credit: 'Photo by Brooke Lark on Unsplash', creditUrl: 'https://unsplash.com/photos/HlNcigvUi4Q' },
    { url: 'https://images.unsplash.com/photo-1467003909585-2f8a72700288?w=1200&h=800&fit=crop&fm=webp&q=80', credit: 'Photo by Brooke Lark on Unsplash', creditUrl: 'https://unsplash.com/photos/jUPOXXRNdcA' },
    { url: 'https://images.unsplash.com/photo-1493770348161-369560ae357d?w=1200&h=800&fit=crop&fm=webp&q=80', credit: 'Photo on Unsplash', creditUrl: 'https://unsplash.com' },
    { url: 'https://images.unsplash.com/photo-1540420773420-3366772f4999?w=1200&h=800&fit=crop&fm=webp&q=80', credit: 'Photo on Unsplash', creditUrl: 'https://unsplash.com' },
    { url: 'https://images.unsplash.com/photo-1490474418585-ba9bad8fd0ea?w=1200&h=800&fit=crop&fm=webp&q=80', credit: 'Photo on Unsplash', creditUrl: 'https://unsplash.com' },
    { url: 'https://images.unsplash.com/photo-1543339494-b4cd4f7ba686?w=1200&h=800&fit=crop&fm=webp&q=80', credit: 'Photo on Unsplash', creditUrl: 'https://unsplash.com' },
    { url: 'https://images.unsplash.com/photo-1564834744159-ff0ea41ba4b9?w=1200&h=800&fit=crop&fm=webp&q=80', credit: 'Photo on Unsplash', creditUrl: 'https://unsplash.com' },
    { url: 'https://images.unsplash.com/photo-1565299585323-38d6b0865b47?w=1200&h=800&fit=crop&fm=webp&q=80', credit: 'Photo on Unsplash', creditUrl: 'https://unsplash.com' },
  ];
  const pick = pool[Math.floor(Math.random() * pool.length)];
  imageUrl = pick.url;
  credit = pick.credit;
  creditUrl = pick.creditUrl;
  usedQuery = '(default pool)';
  usedFallback = true;
}

return [{
  json: {
    ...stripData,
    imageUrl,
    credit,
    creditUrl,
    usedQuery,
    usedFallback,
    attemptedQueries: attempted,
  }
}];

const data = $input.first().json;

// --- Replace cover-image placeholders (guarded) ---
let content = data.articleContent || '';
content = content.replace(/^(\s*)\*\s+/gm, '$1- '); // normalize * bullets to -

if (!data.imageUrl) {
  throw new Error('ABORT: no imageUrl set by the Unsplash node — not pushing.');
}
content = content.split('UNSPLASH_PLACEHOLDER').join(data.imageUrl);
content = content.split('CREDIT_PLACEHOLDER').join(data.credit || 'Unsplash');
content = content.split('CREDIT_URL_PLACEHOLDER').join(data.creditUrl || 'https://unsplash.com');

// --- GUARD: no placeholder may survive into the committed file ---
if (/UNSPLASH_PLACEHOLDER|CREDIT_PLACEHOLDER|CREDIT_URL_PLACEHOLDER/.test(content)) {
  throw new Error('ABORT: cover-image placeholders were not fully replaced — not pushing.');
}

// --- Build a safe slug ---
const title = (data.articleTitle || data.topic || '').toString().trim();
if (!title) {
  throw new Error('ABORT: no article title or topic to build a slug from — not pushing.');
}
let slug = title.toLowerCase()
  .replace(/&/g, ' and ')
  .replace(/['’]/g, '')            // drop apostrophes: "beginner's" -> "beginners"
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-+|-+$/g, '');

// Only truncate if genuinely long, and never mid-word
if (slug.length > 80) {
  const cut = slug.slice(0, 80);
  const lastHyphen = cut.lastIndexOf('-');
  slug = (lastHyphen > 30 ? cut.slice(0, lastHyphen) : cut).replace(/-+$/, '');
}

// --- GUARD: slug must be valid ---
if (!slug || slug === 'undefined' || slug === 'null') {
  throw new Error('ABORT: invalid slug ("' + slug + '") for title: ' + title);
}

const encodedContent = Buffer.from(content, 'utf-8').toString('base64');

return [{
  json: {
    topic: data.topic,
    rowNumber: data.rowNumber,
    colA: data.colA,
    colB: data.colB,
    colC: data.colC,
    todayDate: data.todayDate,
    articleTitle: data.articleTitle,
    slug,
    imageUrl: data.imageUrl,
    credit: data.credit,
    creditUrl: data.creditUrl,
    usedFallback: data.usedFallback,
    usedQuery: data.usedQuery,
    articleContent: content,
    encodedContent,
  }
}];
